const __pageData = JSON.parse('{"title":"页式管理基础","description":"","frontmatter":{},"headers":[],"relativePath":"内存管理/3_2 页式管理基础.md","filePath":"内存管理/3_2 页式管理基础.md","lastUpdated":1777187605000}');
